import{_ as t,o,c as r,a2 as i}from"./chunks/framework.C58al07P.js";const m=JSON.parse('{"title":"Ops & Résilience","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/ops-resilience.md","filePath":"fr/guide/ops-resilience.md"}'),s={name:"fr/guide/ops-resilience.md"};function a(l,e,n,d,u,c){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="ops-resilience" tabindex="-1">Ops &amp; Résilience <a class="header-anchor" href="#ops-resilience" aria-label="Permalink to &quot;Ops &amp; Résilience&quot;">​</a></h1><p>Nid offre des outils d&#39;opérations et de résilience pour gérer le stockage, la rétention des archives, le suivi des quotas Gmail API, et l&#39;import/export de mails.</p><hr><h2 id="acceder-a-la-page" tabindex="-1">Accéder à la page <a class="header-anchor" href="#acceder-a-la-page" aria-label="Permalink to &quot;Accéder à la page&quot;">​</a></h2><p>Dans la barre latérale, ouvrez le groupe <strong>Système</strong> et cliquez sur <strong>Ops &amp; Résilience</strong>.</p><p>La page est organisée en 4 onglets :</p><table tabindex="0"><thead><tr><th>Onglet</th><th>Fonctionnalité</th></tr></thead><tbody><tr><td><strong>Stockage S3</strong></td><td>Configuration du stockage distant (S3, MinIO, Backblaze B2)</td></tr><tr><td><strong>Rétention</strong></td><td>Politiques de suppression automatique des archives anciennes</td></tr><tr><td><strong>Quota API</strong></td><td>Suivi en temps réel de la consommation du quota Gmail API</td></tr><tr><td><strong>Import / Export</strong></td><td>Import mbox et IMAP, export mbox</td></tr></tbody></table><hr><h2 id="stockage-distant-s3-minio" tabindex="-1">Stockage distant (S3 / MinIO) <a class="header-anchor" href="#stockage-distant-s3-minio" aria-label="Permalink to &quot;Stockage distant (S3 / MinIO)&quot;">​</a></h2><p>Par défaut, Nid stocke les archives EML sur le système de fichiers local (NAS). Vous pouvez configurer un stockage S3-compatible pour :</p><ul><li><strong>Géo-répliquer</strong> vos archives sur un cloud distant</li><li>Utiliser des services comme <strong>AWS S3</strong>, <strong>MinIO</strong>, <strong>Backblaze B2</strong>, <strong>Wasabi</strong>, etc.</li><li>Séparer le stockage de l&#39;application</li></ul><h3 id="configurer-le-stockage-s3" tabindex="-1">Configurer le stockage S3 <a class="header-anchor" href="#configurer-le-stockage-s3" aria-label="Permalink to &quot;Configurer le stockage S3&quot;">​</a></h3><ol><li>Dans l&#39;onglet <strong>Stockage S3</strong>, sélectionnez le type <strong>S3-compatible</strong></li><li>Renseignez les informations de connexion : <ul><li><strong>Endpoint</strong> : URL de votre serveur S3 (ex. <code>https://s3.amazonaws.com</code> ou <code>https://minio.local:9000</code>)</li><li><strong>Région</strong> : région S3 (ex. <code>us-east-1</code>, <code>eu-west-1</code>)</li><li><strong>Bucket</strong> : nom du bucket de stockage</li><li><strong>Access Key ID</strong> et <strong>Secret Access Key</strong> : identifiants d&#39;accès</li><li><strong>Path-style</strong> : à activer pour MinIO (désactiver pour AWS S3)</li></ul></li><li>Cliquez sur <strong>Tester la connexion</strong> pour vérifier que les identifiants sont corrects</li><li>Cliquez sur <strong>Sauvegarder</strong></li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : formulaire de configuration S3 avec les champs endpoint, région, bucket et les boutons tester/sauvegarder</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Configuration globale vs par utilisateur</p><p>Le stockage S3 peut être configuré de deux manières :</p><ul><li><strong>Globalement</strong> via les variables d&#39;environnement (<code>S3_ENDPOINT</code>, <code>S3_ACCESS_KEY_ID</code>, etc.) — tous les utilisateurs utilisent le même stockage</li><li><strong>Par utilisateur</strong> via l&#39;interface — chaque utilisateur peut configurer son propre stockage S3</li></ul><p>La configuration par utilisateur a priorité sur la configuration globale.</p></div><div class="info custom-block"><p class="custom-block-title">MinIO</p><p>Pour utiliser MinIO (auto-hébergé), activez le <strong>Path-style</strong> et pointez l&#39;endpoint vers votre instance MinIO (ex. <code>http://minio:9000</code>).</p></div><h3 id="revenir-au-stockage-local" tabindex="-1">Revenir au stockage local <a class="header-anchor" href="#revenir-au-stockage-local" aria-label="Permalink to &quot;Revenir au stockage local&quot;">​</a></h3><p>Sélectionnez le type <strong>Local (NAS / disque)</strong> et sauvegardez.</p><hr><h2 id="politiques-de-retention" tabindex="-1">Politiques de rétention <a class="header-anchor" href="#politiques-de-retention" aria-label="Permalink to &quot;Politiques de rétention&quot;">​</a></h2><p>Les politiques de rétention suppriment automatiquement les archives plus anciennes qu&#39;une durée configurable. Cela permet de :</p><ul><li>Libérer de l&#39;espace disque</li><li>Se conformer à des politiques de conservation de données</li><li>Nettoyer automatiquement les vieilles archives</li></ul><h3 id="creer-une-politique" tabindex="-1">Créer une politique <a class="header-anchor" href="#creer-une-politique" aria-label="Permalink to &quot;Créer une politique&quot;">​</a></h3><ol><li>Dans l&#39;onglet <strong>Rétention</strong>, cliquez sur <strong>Nouvelle politique</strong></li><li>Renseignez : <ul><li><strong>Nom</strong> : nom descriptif (ex. « Archives &gt; 2 ans »)</li><li><strong>Compte</strong> : optionnel — pour cibler un compte Gmail spécifique, ou tous</li><li><strong>Label</strong> : optionnel — pour cibler uniquement les mails avec un label particulier</li><li><strong>Jours de rétention</strong> : durée maximale en jours (ex. 365 pour 1 an, 730 pour 2 ans)</li></ul></li><li>Cliquez sur <strong>Créer</strong></li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : formulaire de création de politique de rétention</em></p></blockquote><h3 id="gerer-les-politiques" tabindex="-1">Gérer les politiques <a class="header-anchor" href="#gerer-les-politiques" aria-label="Permalink to &quot;Gérer les politiques&quot;">​</a></h3><ul><li><strong>Activer / Désactiver</strong> : utilisez le switch pour activer ou désactiver une politique sans la supprimer</li><li><strong>Supprimer</strong> : supprime définitivement la politique</li><li><strong>Exécuter maintenant</strong> : lance manuellement l&#39;application de toutes les politiques actives</li></ul><p>Le tableau affiche pour chaque politique :</p><table tabindex="0"><thead><tr><th>Colonne</th><th>Description</th></tr></thead><tbody><tr><td>Nom</td><td>Nom de la politique</td></tr><tr><td>Compte</td><td>Compte Gmail ciblé (ou « Tous »)</td></tr><tr><td>Label</td><td>Label Gmail ciblé (ou « — »)</td></tr><tr><td>Durée max</td><td>Âge maximum des archives</td></tr><tr><td>Supprimés</td><td>Nombre total d&#39;archives supprimées depuis la création</td></tr><tr><td>Dernière exécution</td><td>Date de la dernière application</td></tr><tr><td>Actif</td><td>État de la politique</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Suppression irréversible</p><p>Les archives supprimées par une politique de rétention sont définitivement effacées (fichier EML + entrée en base de données). Cette action est irréversible.</p></div><hr><h2 id="dashboard-quota-gmail-api" tabindex="-1">Dashboard quota Gmail API <a class="header-anchor" href="#dashboard-quota-gmail-api" aria-label="Permalink to &quot;Dashboard quota Gmail API&quot;">​</a></h2><p>Google impose un quota de <strong>250 unités par utilisateur par seconde</strong> sur l&#39;API Gmail. Chaque appel consomme un nombre d&#39;unités variable (ex. <code>messages.get</code> = 5 unités, <code>messages.send</code> = 100 unités).</p><p>Le dashboard quota vous permet de :</p><ul><li><strong>Surveiller</strong> votre consommation en temps réel</li><li><strong>Identifier</strong> les endpoints les plus consommateurs</li><li><strong>Anticiper</strong> les dépassements de quota</li></ul><h3 id="lecture-du-dashboard" tabindex="-1">Lecture du dashboard <a class="header-anchor" href="#lecture-du-dashboard" aria-label="Permalink to &quot;Lecture du dashboard&quot;">​</a></h3><p>L&#39;onglet <strong>Quota API</strong> affiche :</p><table tabindex="0"><thead><tr><th>Bloc</th><th>Description</th></tr></thead><tbody><tr><td><strong>Dernière minute</strong></td><td>Unités consommées + pourcentage du plafond (barre de progression colorée)</td></tr><tr><td><strong>Dernière heure</strong></td><td>Total d&#39;unités et de requêtes sur l&#39;heure écoulée</td></tr><tr><td><strong>24 dernières heures</strong></td><td>Total d&#39;unités et de requêtes sur la journée</td></tr><tr><td><strong>Top endpoints</strong></td><td>Classement des endpoints les plus gourmands (24h)</td></tr><tr><td><strong>Historique horaire</strong></td><td>Tableau détaillé heure par heure (24h)</td></tr></tbody></table><blockquote><p>📸 <em>Capture d&#39;écran suggérée : dashboard quota avec les 3 statistiques en haut, le tableau des endpoints au milieu et l&#39;historique horaire en bas</em></p></blockquote><div class="info custom-block"><p class="custom-block-title">Rafraîchissement automatique</p><p>Les données du quota sont actualisées automatiquement <strong>toutes les 30 secondes</strong>.</p></div><h3 id="couts-des-endpoints-gmail-api" tabindex="-1">Coûts des endpoints Gmail API <a class="header-anchor" href="#couts-des-endpoints-gmail-api" aria-label="Permalink to &quot;Coûts des endpoints Gmail API&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Endpoint</th><th>Unités</th></tr></thead><tbody><tr><td><code>messages.get</code></td><td>5</td></tr><tr><td><code>messages.list</code></td><td>5</td></tr><tr><td><code>messages.send</code></td><td>100</td></tr><tr><td><code>messages.modify</code></td><td>5</td></tr><tr><td><code>messages.trash</code></td><td>5</td></tr><tr><td><code>messages.delete</code></td><td>10</td></tr><tr><td><code>messages.batchModify</code></td><td>50</td></tr><tr><td><code>messages.batchDelete</code></td><td>50</td></tr><tr><td><code>labels.list</code> / <code>labels.get</code></td><td>1</td></tr></tbody></table><hr><h2 id="import-de-mails" tabindex="-1">Import de mails <a class="header-anchor" href="#import-de-mails" aria-label="Permalink to &quot;Import de mails&quot;">​</a></h2><p>Nid permet d&#39;importer des mails depuis des sources externes dans vos archives.</p><h3 id="import-mbox" tabindex="-1">Import Mbox <a class="header-anchor" href="#import-mbox" aria-label="Permalink to &quot;Import Mbox&quot;">​</a></h3><p>Le format <strong>mbox</strong> est un standard utilisé par Google Takeout, Thunderbird, Apple Mail et d&#39;autres clients email. Il regroupe plusieurs mails dans un seul fichier.</p><ol><li>Dans l&#39;onglet <strong>Import / Export</strong>, section <strong>Import Mbox</strong>, déposez votre fichier <code>.mbox</code></li><li>Un job d&#39;import est créé — suivez sa progression dans la page <strong>Jobs</strong></li><li>Chaque mail du fichier mbox est converti en EML individuel et ajouté à vos archives</li></ol><p>Le processus :</p><ul><li>Parse chaque message du fichier mbox</li><li>Extrait les métadonnées (sujet, expéditeur, date, pièces jointes)</li><li>Vérifie les doublons (skip si le Message-ID existe déjà)</li><li>Stocke le fichier EML + les pièces jointes séparément</li><li>Indexe le mail dans PostgreSQL (recherche full-text)</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : zone de drag &amp; drop pour le fichier mbox</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Google Takeout</p><p>Pour exporter vos mails depuis Gmail :</p><ol><li>Allez sur <a href="https://takeout.google.com" target="_blank" rel="noreferrer">takeout.google.com</a></li><li>Sélectionnez uniquement <strong>Gmail</strong></li><li>Choisissez le format <strong>mbox</strong></li><li>Téléchargez l&#39;archive et importez le fichier <code>.mbox</code> dans Nid</li></ol></div><h3 id="import-imap" tabindex="-1">Import IMAP <a class="header-anchor" href="#import-imap" aria-label="Permalink to &quot;Import IMAP&quot;">​</a></h3><p>Importez directement des mails depuis un serveur IMAP (Outlook, ProtonMail, Yahoo, etc.) :</p><ol><li>Dans la section <strong>Import IMAP</strong>, renseignez : <ul><li><strong>Serveur IMAP</strong> : adresse du serveur (ex. <code>imap.outlook.com</code>)</li><li><strong>Port</strong> : port du serveur (défaut : 993)</li><li><strong>Identifiant</strong> : votre login email</li><li><strong>Mot de passe</strong> : votre mot de passe ou mot de passe d&#39;application</li><li><strong>Dossier</strong> : dossier IMAP à importer (défaut : <code>INBOX</code>)</li><li><strong>Max messages</strong> : optionnel — limiter le nombre de mails importés</li><li><strong>Connexion sécurisée</strong> : TLS activé par défaut</li></ul></li><li>Cliquez sur <strong>Lancer l&#39;import</strong></li><li>Un job est créé — suivez sa progression dans la page <strong>Jobs</strong></li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : formulaire d&#39;import IMAP avec les champs serveur, port, identifiant et mot de passe</em></p></blockquote><div class="warning custom-block"><p class="custom-block-title">Mot de passe d&#39;application</p><p>De nombreux providers (Google, Outlook, Yahoo) nécessitent un <strong>mot de passe d&#39;application</strong> spécifique plutôt que votre mot de passe habituel. Consultez la documentation de votre fournisseur email.</p></div><div class="info custom-block"><p class="custom-block-title">Serveurs IMAP courants</p><table tabindex="0"><thead><tr><th>Provider</th><th>Serveur</th><th>Port</th></tr></thead><tbody><tr><td>Outlook / Hotmail</td><td><code>imap-mail.outlook.com</code></td><td>993</td></tr><tr><td>Yahoo</td><td><code>imap.mail.yahoo.com</code></td><td>993</td></tr><tr><td>ProtonMail (Bridge)</td><td><code>127.0.0.1</code></td><td>1143</td></tr><tr><td>OVH</td><td><code>ssl0.ovh.net</code></td><td>993</td></tr><tr><td>Free</td><td><code>imap.free.fr</code></td><td>993</td></tr></tbody></table></div><hr><h2 id="export-mbox" tabindex="-1">Export Mbox <a class="header-anchor" href="#export-mbox" aria-label="Permalink to &quot;Export Mbox&quot;">​</a></h2><p>Exportez vos archives au format mbox, compatible avec la plupart des clients email :</p><ol><li>Dans la section <strong>Export Mbox</strong>, cliquez sur <strong>Exporter en .mbox</strong></li><li>Le fichier est généré et téléchargé automatiquement</li></ol><p>Le fichier mbox contient tous vos mails archivés du compte sélectionné, au format standard RFC 4155.</p><div class="tip custom-block"><p class="custom-block-title">Réimportation</p><p>Le fichier mbox exporté peut être importé dans Thunderbird, Apple Mail ou toute autre application compatible. C&#39;est un bon moyen de sauvegarder vos archives dans un format universel.</p></div>',64)])])}const g=t(s,[["render",a]]);export{m as __pageData,g as default};
